        break;
      }
#endif /* defined(SQLITE_BUILDING_FOR_COMDB2) */
    }
    if( iCol<0 ){
      /* This case is when the phase presets zCurrentRow */
      if( pCur->zCurrentRow==0 ) continue;
    }else{
